def solve(s: String): String = {
  var result = List[Char]()

  for (c <- s) {
    c match {
      case 'a' to 'z' => result = c :: result
      case '*' => result = result.init
      case '#' => result = result ++ result
      case '%' => result = result.reverse
    }
  }

  result.mkString
}
